queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?director a :Director .
    ?director p:name ?name .
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?producer a :Producer .
    ?producer p:name ?name .
    ?producer p:Award ?award_f .
    FILTER(STR(?award_f) = "Oscar")
    BIND(?name AS ?o0)
  }
}

